export const sampleBusinessRule: MetadataRecord = { sys_id: "br001", name: "Set Assignment Group on Priority Change", table: "incident", active: true, script: `(function executeRule(current, previous) {\n  if (current.assignment_group.changes()) {\n    var gr = new GlideRecord('sys_user_group');\n    gr.get(current.assignment_group);\n  }\n  if (previous.assignment_group != current.assignment_group) {\n    gs.eventQueue('incident.assignment.changed', current, current.assignment_group, previous.assignment_group);\n  }\n})(current, previous);`, description: "Logs work note", type: "business_rule", extra: { when: "after", order: "100", filter_condition: "assignment_groupCHANGES", action_update: true } };
export const sampleClientScript: MetadataRecord = { sys_id: "cs001", name: "Validate Assignment Group", table: "incident", active: true, script: `function onChange(control, oldValue, newValue, isLoading) {\n  if (isLoading) return;\n  var ag = g_form.getValue('assignment_group');\n  if (ag) g_form.getReference('assignment_group', function(ref) { if (ref.type === 'hardware') g_form.setValue('category', 'hardware'); });\n}`, description: "Sets category", type: "client_script", extra: { script_type: "onChange", field_name: "assignment_group" } };
