export const sampleScriptInclude: MetadataRecord = { sys_id: "si001", name: "IncidentUtils", table: "", active: true, script: `var IncidentUtils = Class.create();\nIncidentUtils.prototype = {\n  initialize: function() {},\n  getMembers: function(gr) {\n    var gid = gr.getValue('assignment_group');\n    return gid;\n  },\n  reassign: function(id, newGroup) {\n    var gr = new GlideRecord('incident');\n    if (gr.get(id)) {\n      gr.assignment_group = newGroup;\n      gr.update();\n    }\n  },\n  type: 'IncidentUtils'\n};`, description: "Utility functions", type: "script_include", extra: { api_name: "global.IncidentUtils" } };
